package com.forgeboard.work.application;
import static org.assertj.core.api.Assertions.assertThat; import static org.mockito.Mockito.when;
import java.math.BigDecimal; import java.time.*; import java.util.*; import org.junit.jupiter.api.*; import org.junit.jupiter.api.extension.ExtendWith; import org.mockito.*; import org.mockito.junit.jupiter.MockitoExtension;
import com.forgeboard.identity.SelectedTenant; import com.forgeboard.identity.domain.MembershipRole; import com.forgeboard.work.domain.*; import com.forgeboard.work.persistence.*;
@ExtendWith(MockitoExtension.class) class DeadlineDashboardServiceTest { @Mock WorkItemRepository items; @Mock WorkflowStageRepository stages; DeadlineDashboardService service; SelectedTenant tenant; Instant now;
 @BeforeEach void setUp(){now=Instant.parse("2026-07-13T00:00:00Z");tenant=new SelectedTenant(UUID.randomUUID(),UUID.randomUUID(),"owner@example.com",MembershipRole.OWNER);service=new DeadlineDashboardService(items,stages,Clock.fixed(now,ZoneOffset.UTC));}
 @Test void groupsOverdueAndReviewWork(){UUID workflow=UUID.randomUUID(), review=UUID.randomUUID(), blocked=UUID.randomUUID();when(stages.findAllByFirmIdOrderByWorkflowIdAscPositionAsc(tenant.firmId())).thenReturn(List.of(new WorkflowStage(review,tenant.firmId(),workflow,"Ready for review",0,now),new WorkflowStage(blocked,tenant.firmId(),workflow,"Blocked",1,now)));when(items.findAllByFirmIdOrderByDueDateAsc(tenant.firmId())).thenReturn(List.of(item(workflow,review,LocalDate.of(2026,7,12)),item(workflow,blocked,null)));var dashboard=service.overview(tenant);assertThat(dashboard.overdueCount()).isEqualTo(1);assertThat(dashboard.blockedCount()).isEqualTo(1);assertThat(dashboard.awaitingReviewCount()).isZero();}
 private WorkItem item(UUID workflow,UUID stage,LocalDate due){return new WorkItem(UUID.randomUUID(),tenant.firmId(),UUID.randomUUID(),workflow,stage,"Item","",due,WorkPriority.NORMAL,BigDecimal.ONE,now);}}
